/**
 * MedX landmarks accessibility runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Page landmark roles and labeling.
 */
const LANDMARKS_TOKENS = Object.freeze({
  primary: { value: "a11y-landmarks-primary", scope: "a11y" },
  secondary: { value: "a11y-landmarks-secondary", scope: "a11y" },
  muted: { value: "a11y-landmarks-muted", scope: "a11y" },
  accent: { value: "a11y-landmarks-accent", scope: "a11y" },
  surface: { value: "a11y-landmarks-surface", scope: "a11y" },
});

const LANDMARKS_PRESETS = Object.freeze({
  default: { token: "primary", enabled: true, priority: 1 },
  compact: { token: "secondary", enabled: true, priority: 2 },
  emphasis: { token: "accent", enabled: true, priority: 3 },
  subtle: { token: "muted", enabled: true, priority: 4 },
});

const LANDMARKS_SUPPLY_CHAIN = Object.freeze({
  inventory: { label: "Inventory", key: "inventory", tier: "ops" },
  orders: { label: "Orders", key: "orders", tier: "ops" },
  compliance: { label: "Compliance", key: "compliance", tier: "regulatory" },
  coldChain: { label: "Cold chain", key: "cold-chain", tier: "ops" },
  blockchain: { label: "Blockchain", key: "blockchain", tier: "integrations" },
});

const landmarksRegistry = new Map();
const LANDMARKS_listeners = new Set();
let LANDMARKS_seq = 0;

function createLandmarksId(prefix = "medx-a11y-landmarks") {
  LANDMARKS_seq += 1;
  return `${prefix}-${LANDMARKS_seq}`;
}

function registerLandmarks(config = {}) {
  const entryId = config.id ?? createLandmarksId();
  const preset = LANDMARKS_PRESETS[config.preset ?? "default"] ?? LANDMARKS_PRESETS.default;
  const token = LANDMARKS_TOKENS[config.token ?? preset.token] ?? LANDMARKS_TOKENS.primary;
  const entry = {
    id: entryId,
    preset: config.preset ?? "default",
    token,
    domain: config.domain ?? "inventory",
    domainMeta: LANDMARKS_SUPPLY_CHAIN[config.domain ?? "inventory"] ?? null,
    enabled: config.enabled ?? preset.enabled,
    priority: config.priority ?? preset.priority,
    metadata: config.metadata ?? {},
    createdAt: Date.now(),
    onChange: typeof config.onChange === "function" ? config.onChange : null,
  };
  landmarksRegistry.set(entryId, entry);
  notifyLandmarksListeners("register", entry);
  return entry;
}

function updateLandmarks(id, patch = {}) {
  const entry = landmarksRegistry.get(id);
  if (!entry) return null;
  Object.assign(entry, patch, { updatedAt: Date.now() });
  if (entry.onChange) entry.onChange(entry);
  notifyLandmarksListeners("update", entry);
  return entry;
}

function resolveLandmarks(id) {
  const entry = landmarksRegistry.get(id);
  if (!entry) return null;
  return {
    id: entry.id,
    token: entry.token.value,
    domain: entry.domain,
    enabled: entry.enabled,
    priority: entry.priority,
    label: entry.domainMeta?.label ?? entry.domain,
  };
}

function listLandmarksEntries(filter = {}) {
  let items = Array.from(landmarksRegistry.values());
  if (filter.domain) items = items.filter((e) => e.domain === filter.domain);
  if (filter.enabled != null) items = items.filter((e) => e.enabled === filter.enabled);
  return items.sort((a, b) => a.priority - b.priority);
}

function onLandmarksEvent(listener) {
  LANDMARKS_listeners.add(listener);
  return () => LANDMARKS_listeners.delete(listener);
}

function notifyLandmarksListeners(type, entry) {
  for (const listener of LANDMARKS_listeners) {
    try {
      listener({ type, entry, registrySize: landmarksRegistry.size });
    } catch (err) {
      console.warn("[medx:ui:a11y:landmarks] listener error", err.message);
    }
  }
}

function getLandmarksMetrics() {
  const items = listLandmarksEntries();
  return {
    total: items.length,
    enabled: items.filter((e) => e.enabled).length,
    domains: [...new Set(items.map((e) => e.domain))],
    tokens: Object.keys(LANDMARKS_TOKENS).length,
    presets: Object.keys(LANDMARKS_PRESETS).length,
  };
}

async function runMedxLandmarks() {
  console.log("[medx:ui:a11y:landmarks] runtime initialized");
  console.log(`[medx:ui:a11y:landmarks] tokens=${Object.keys(LANDMARKS_TOKENS).length} presets=${Object.keys(LANDMARKS_PRESETS).length}`);

  const events = [];
  onLandmarksEvent((e) => events.push(e.type));

  const domains = Object.keys(LANDMARKS_SUPPLY_CHAIN);
  const presets = Object.keys(LANDMARKS_PRESETS);
  for (let i = 0; i < domains.length; i += 1) {
    registerLandmarks({
      domain: domains[i],
      preset: presets[i % presets.length],
      metadata: { seed: i, module: "a11y/landmarks" },
    });
  }

  const first = listLandmarksEntries()[0];
  if (first) updateLandmarks(first.id, { priority: 0, metadata: { ...first.metadata, promoted: true } });

  const metrics = getLandmarksMetrics();
  const resolved = first ? resolveLandmarks(first.id) : null;

  console.log(`[medx:ui:a11y:landmarks] registered=${metrics.total} enabled=${metrics.enabled}`);
  console.log(`[medx:ui:a11y:landmarks] domains=${metrics.domains.join(",")}`);
  console.log(`[medx:ui:a11y:landmarks] events=${events.join(",")}`);
  if (resolved) console.log(`[medx:ui:a11y:landmarks] sample=${resolved.token}:${resolved.domain}`);
  console.log("[medx:ui:a11y:landmarks] bootstrap complete");
}

module.exports = runMedxLandmarks;
